//#region src/adapter/node.ts
const nodeAdapter = () => {
	if (typeof globalThis.navigator === "undefined") globalThis.navigator = { userAgent: "Node.js" };
	else Object.defineProperty(globalThis.navigator, "userAgent", {
		value: "Node.js",
		writable: false
	});
	return { env: process.env };
};
//#endregion
export { nodeAdapter as default, nodeAdapter };
